/**
 * High-precision clock implementation using Web Audio API and Performance.now()
 * Provides microsecond-level timing accuracy for psychological experiments
 */

export interface TimingContext {
  readonly audioContext: AudioContext;
  readonly baseTime: number;
  readonly performanceOrigin: number;
}

export interface PrecisionTimestamp {
  readonly audioTime: number;
  readonly performanceTime: number;
  readonly rafTime: number;
  readonly monotonic: number;
}

export class PrecisionClock {
  private audioContext: AudioContext | null = null;
  private baseTime: number = 0;
  private performanceOrigin: number = 0;
  private rafCallbacks: Array<(timestamp: number) => void> = [];
  private isRunning: boolean = false;
  private rafId: number | null = null;

  constructor() {
    this.performanceOrigin = performance.timeOrigin || 0;
  }

  /**
   * Initialize the precision clock with Web Audio API
   */
  async initialize(): Promise<TimingContext> {
    if (this.audioContext) {
      throw new Error('PrecisionClock already initialized');
    }

    try {
      // Create AudioContext for hardware-level timing
      this.audioContext = new AudioContext();

      // Resume if suspended (required by browser autoplay policies)
      if (this.audioContext.state === 'suspended') {
        await this.audioContext.resume();
      }

      // Establish baseline timing relationship
      this.baseTime = this.audioContext.currentTime;

      // Start RAF loop for display synchronization
      this.startRafLoop();

      return {
        audioContext: this.audioContext,
        baseTime: this.baseTime,
        performanceOrigin: this.performanceOrigin
      };
    } catch (error) {
      throw new Error(`Failed to initialize PrecisionClock: ${error}`);
    }
  }

  /**
   * Get current high-precision timestamp
   */
  now(): PrecisionTimestamp {
    if (!this.audioContext) {
      throw new Error('PrecisionClock not initialized');
    }

    const audioTime = this.audioContext.currentTime;
    const performanceTime = performance.now();
    const rafTime = this.lastRafTimestamp || performanceTime;

    // Create monotonic timestamp combining both clocks
    const monotonic = this.createMonotonicTimestamp(audioTime, performanceTime);

    return {
      audioTime,
      performanceTime,
      rafTime,
      monotonic
    };
  }

  /**
   * Schedule a callback to run at a specific audio time
   */
  scheduleCallback(targetTime: number, callback: () => void): void {
    if (!this.audioContext) {
      throw new Error('PrecisionClock not initialized');
    }

    // Use AudioContext's precise scheduling
    const oscillator = this.audioContext.createOscillator();
    const gainNode = this.audioContext.createGain();

    oscillator.connect(gainNode);
    gainNode.connect(this.audioContext.destination);

    // Set gain to 0 to prevent audio output
    gainNode.gain.value = 0;

    oscillator.start(targetTime);
    oscillator.stop(targetTime + 0.001); // Very short duration

    oscillator.onended = () => {
      callback();
    };
  }

  /**
   * Register for RequestAnimationFrame callbacks
   */
  onFrame(callback: (timestamp: number) => void): () => void {
    this.rafCallbacks.push(callback);

    // Return unsubscribe function
    return () => {
      const index = this.rafCallbacks.indexOf(callback);
      if (index > -1) {
        this.rafCallbacks.splice(index, 1);
      }
    };
  }

  /**
   * Get timing precision estimate in microseconds
   */
  getPrecisionEstimate(): number {
    if (!this.audioContext) {
      throw new Error('PrecisionClock not initialized');
    }

    // Sample timing resolution by taking multiple measurements
    const samples: number[] = [];
    const sampleCount = 100;

    for (let i = 0; i < sampleCount; i++) {
      const start = performance.now();
      void this.audioContext.currentTime; // Force access to measure timing overhead
      const end = performance.now();

      samples.push(end - start);
    }

    // Return minimum observed resolution in microseconds
    return Math.min(...samples) * 1000;
  }

  /**
   * Check if high-precision timing is available
   */
  isHighPrecisionAvailable(): boolean {
    return !!(
      this.audioContext &&
      this.audioContext.sampleRate >= 44100 &&
      typeof performance !== 'undefined' &&
      typeof performance.now === 'function' &&
      typeof requestAnimationFrame === 'function'
    );
  }

  /**
   * Destroy the precision clock and clean up resources
   */
  async destroy(): Promise<void> {
    this.isRunning = false;

    if (this.rafId) {
      cancelAnimationFrame(this.rafId);
      this.rafId = null;
    }

    if (this.audioContext) {
      await this.audioContext.close();
      this.audioContext = null;
    }

    this.rafCallbacks = [];
  }

  private lastRafTimestamp: number = 0;

  private startRafLoop(): void {
    if (this.isRunning) return;

    this.isRunning = true;

    const rafLoop = (timestamp: number) => {
      this.lastRafTimestamp = timestamp;

      // Call all registered frame callbacks
      this.rafCallbacks.forEach(callback => {
        try {
          callback(timestamp);
        } catch (error) {
          console.error('Error in RAF callback:', error);
        }
      });

      if (this.isRunning) {
        this.rafId = requestAnimationFrame(rafLoop);
      }
    };

    this.rafId = requestAnimationFrame(rafLoop);
  }

  private createMonotonicTimestamp(audioTime: number, performanceTime: number): number {
    // Create a monotonic timestamp that combines both clocks
    // Use audio time as primary (more stable) with performance time as fallback
    const audioMs = audioTime * 1000;
    const performanceMs = performanceTime;

    // Use weighted average favoring audio time
    return (audioMs * 0.8) + (performanceMs * 0.2);
  }
}

/**
 * Singleton instance for global access
 */
export const precisionClock = new PrecisionClock();

