/**
 * @psyforge/timing - High-precision timing system for psychological experiments
 * 
 * Provides microsecond-level timing accuracy using Web Audio API and Performance API
 * for reliable stimulus presentation and response collection in behavioral research.
 */

export {
  PrecisionClock,
  precisionClock,
  type TimingContext,
  type PrecisionTimestamp
} from './PrecisionClock.js';

export {
  TimingDriftDetector,
  createDriftDetector,
  type DriftMeasurement,
  type DriftStatus
} from './TimingDriftDetector.js';

/**
 * Check if high-precision timing is supported in current environment
 */
export function isTimingSupported(): boolean {
  return !!(
    typeof AudioContext !== 'undefined' &&
    typeof performance !== 'undefined' &&
    typeof performance.now === 'function' &&
    typeof requestAnimationFrame === 'function'
  );
}

/**
 * Get estimated timing precision for current environment
 */
export async function getTimingCapabilities(): Promise<{
  supported: boolean;
  audioContextSupported: boolean;
  performanceSupported: boolean;
  rafSupported: boolean;
  estimatedPrecision: number;
}> {
  const audioContextSupported = typeof AudioContext !== 'undefined';
  const performanceSupported = typeof performance !== 'undefined' && typeof performance.now === 'function';
  const rafSupported = typeof requestAnimationFrame === 'function';
  const supported = audioContextSupported && performanceSupported && rafSupported;

  let estimatedPrecision = 0;

  if (supported) {
    try {
      // Quick precision test
      const samples: number[] = [];
      for (let i = 0; i < 10; i++) {
        const start = performance.now();
        const end = performance.now();
        samples.push(end - start);
      }
      const validSamples = samples.filter(s => s > 0);
      estimatedPrecision = validSamples.length > 0 ? Math.min(...validSamples) * 1000 : Infinity;
    } catch (error) {
      estimatedPrecision = 0;
      throw error;
    }
  }

  return {
    supported,
    audioContextSupported,
    performanceSupported,
    rafSupported,
    estimatedPrecision
  };
}

/**
 * @psyforge/scheduler - Hierarchical task scheduler for precise experiment execution
 * 
 * Provides frame-accurate timing control, priority-based scheduling, and
 * hierarchical timeline management for behavioral research experiments.
 */

// Core scheduler
export { Scheduler, type SchedulerOptions, type SchedulerMetrics } from './Scheduler.js';
import { Scheduler, type SchedulerOptions } from './Scheduler.js';

// Task management
export { 
  Task, 
  TaskState,
  type TaskContext, 
  type TaskFunction, 
  type TaskCompletionCallback,
  type TaskOptions 
} from './Task.js';
import { Task, type TaskFunction, type TaskOptions } from './Task.js';

// Priority system
export { TaskPriority, TaskPriorityUtils } from './TaskPriority.js';
import { TaskPriority } from './TaskPriority.js';

// Timeline hierarchy
export { 
  Timeline, 
  TimelineState,
  type TimelineEvent, 
  type TimelineOptions 
} from './Timeline.js';
import { Timeline, type TimelineOptions } from './Timeline.js';

/**
 * Create a new scheduler instance with default configuration
 * optimized for psychological experiments
 */
export function createScheduler(options: SchedulerOptions = {}): Scheduler {
  return new Scheduler({
    maxTasksPerFrame: 10,
    frameTimeBudget: 8, // 8ms for 120fps headroom
    useHighPrecisionTiming: true,
    timingTolerance: 2, // 2ms tolerance for ≤2ms target
    allowPreemption: true,
    ...options
  });
}

/**
 * Create a new timeline with experiment-friendly defaults
 */
export function createTimeline(name: string, options: Omit<TimelineOptions, 'name'> = {}): Timeline {
  return new Timeline({
    name,
    defaultPriority: TaskPriority.NORMAL,
    repeatable: false,
    repetitions: 1,
    ...options
  });
}

/**
 * Create a repeating timeline for trial-based experiments
 */
export function createTrialTimeline(
  name: string, 
  repetitions: number, 
  repetitionDelay: number = 0,
  options: Omit<TimelineOptions, 'name' | 'repeatable' | 'repetitions' | 'repetitionDelay'> = {}
): Timeline {
  return new Timeline({
    name,
    repeatable: true,
    repetitions,
    repetitionDelay,
    defaultPriority: TaskPriority.NORMAL,
    ...options
  });
}

/**
 * Helper to create a task with common experiment patterns
 */
export function createTask(
  name: string,
  execute: TaskFunction,
  priority: TaskPriority = TaskPriority.NORMAL,
  options: Omit<TaskOptions, 'priority'> = {}
): Task {
  return new Task(name, execute, { priority, ...options });
}

/**
 * Helper to create a stimulus presentation task
 */
export function createStimulusTask(
  name: string,
  stimulusFunction: TaskFunction,
  options: TaskOptions = {}
): Task {
  return new Task(name, stimulusFunction, {
    priority: TaskPriority.HIGH, // Stimulus presentation is high priority
    timeout: 10000, // 10 second timeout for stimuli
    interruptible: false, // Don't interrupt stimulus presentation
    ...options
  });
}

/**
 * Helper to create a response collection task
 */
export function createResponseTask(
  name: string,
  responseFunction: TaskFunction,
  timeoutMs: number = 5000,
  options: Omit<TaskOptions, 'timeout' | 'priority'> = {}
): Task {
  return new Task(name, responseFunction, {
    priority: TaskPriority.CRITICAL, // Response collection is critical
    timeout: timeoutMs,
    interruptible: true, // Can be interrupted by timeout
    ...options
  });
}

/**
 * Version information
 */
export const VERSION = '0.1.0';

