// Core classes
export { Timeline, type TimelineItem, type TimelineContext, type TimelineOptions } from './core/Timeline.js';
export { 
  Event, 
  WaitEvent, 
  ConditionalEvent, 
  LoopEvent, 
  DataEvent,
  type EventOptions 
} from './core/Event.js';
export { 
  Experiment, 
  type ExperimentMetadata, 
  type ExperimentData, 
  type ExperimentOptions 
} from './core/Experiment.js';
export { 
  Runtime, 
  type RuntimeConfiguration, 
  type RuntimeCapabilities 
} from './core/Runtime.js';

// Stimulus classes
export { 
  TextStimulus, 
  type TextStimulusOptions 
} from './stimuli/Text.js';
export { 
  ImageStimulus, 
  type ImageStimulusOptions 
} from './stimuli/Image.js';
export { 
  AudioStimulus, 
  type AudioStimulusOptions 
} from './stimuli/Audio.js';
export { 
  VideoStimulus, 
  type VideoStimulusOptions 
} from './stimuli/Video.js';

// Response classes
export { 
  KeyboardResponse, 
  type KeyboardResponseData, 
  type KeyboardResponseOptions 
} from './responses/KeyboardResponse.js';
export { 
  MouseResponse, 
  type MouseResponseData, 
  type MouseResponseOptions 
} from './responses/MouseResponse.js';
export { 
  TouchResponse, 
  type TouchResponseData, 
  type TouchResponseOptions 
} from './responses/TouchResponse.js';

// Serialization and validation
export { 
  Serializer, 
  type SerializationOptions, 
  type SerializedExperiment 
} from './serialization/Serializer.js';
export { 
  Validator, 
  type ValidationResult, 
  type ValidationError, 
  type ValidationWarning, 
  type ValidationOptions 
} from './serialization/Validator.js';

// Helper functions and utilities
export const ForgeScript = {
  // Factory functions for common patterns
  createExperiment: (title: string, options?: ExperimentOptions) => {
    return new Experiment(crypto.randomUUID(), options).title(title);
  },

  createTimeline: (id: string) => {
    return new Timeline(id);
  },

  createTextStimulus: (text: string, duration?: number) => {
    const stimulus = new TextStimulus(crypto.randomUUID(), text);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createImageStimulus: (src: string, duration?: number) => {
    const stimulus = new ImageStimulus(crypto.randomUUID(), src);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createAudioStimulus: (src: string, duration?: number) => {
    const stimulus = new AudioStimulus(crypto.randomUUID(), src);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createVideoStimulus: (src: string, duration?: number) => {
    const stimulus = new VideoStimulus(crypto.randomUUID(), src);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createKeyboardResponse: (keys?: string[], timeout?: number) => {
    const response = new KeyboardResponse(crypto.randomUUID());
    if (keys) response.keys(keys);
    if (timeout !== undefined) response.timeout(timeout);
    return response;
  },

  createMouseResponse: (timeout?: number) => {
    const response = new MouseResponse(crypto.randomUUID());
    if (timeout !== undefined) response.timeout(timeout);
    return response;
  },

  createTouchResponse: (timeout?: number) => {
    const response = new TouchResponse(crypto.randomUUID());
    if (timeout !== undefined) response.timeout(timeout);
    return response;
  },

  createWaitEvent: (duration: number) => {
    return new WaitEvent(crypto.randomUUID(), duration);
  },

  // Quick experiment runners
  runExperiment: async (experiment: Experiment, participantId?: string) => {
    return await Runtime.quickRun(experiment, participantId);
  },

  // Serialization helpers
  saveExperiment: (experiment: Experiment, options?: SerializationOptions) => {
    return Serializer.stringify(experiment, options);
  },

  loadExperiment: (jsonString: string) => {
    return Serializer.parse(jsonString);
  },

  // Validation helpers
  validateExperiment: (experiment: Experiment, options?: ValidationOptions) => {
    return Validator.validateExperiment(experiment, options);
  },

  // Runtime management
  createRuntime: async (config?: RuntimeConfiguration) => {
    return await Runtime.createAndInitialize(config);
  },

  // Common experiment patterns
  createStroop: (words: string[], colors: string[], trials: number = 20) => {
    const experiment = ForgeScript.createExperiment('Stroop Task')
      .description('Classic Stroop color-word interference task')
      .author('Generated by ForgeScript');

    // Welcome timeline
    const welcome = ForgeScript.createTimeline('welcome')
      .add(ForgeScript.createTextStimulus('Welcome to the Stroop Task!', 2000))
      .add(ForgeScript.createTextStimulus('Press SPACE to continue'))
      .add(ForgeScript.createKeyboardResponse(['space']));

    // Instructions timeline
    const instructions = ForgeScript.createTimeline('instructions')
      .add(ForgeScript.createTextStimulus(
        'Name the COLOR of each word, not the word itself.\nPress F for red, G for green, H for blue.\nPress SPACE to start.',
        5000
      ))
      .add(ForgeScript.createKeyboardResponse(['space']));

    // Trial timeline
    const trialTimeline = ForgeScript.createTimeline('trials')
      .repeat(trials)
      .randomize()
      .add(ForgeScript.createTextStimulus('+', 500)) // fixation
      .add(ForgeScript.createTextStimulus((context) => {
        const word = words[Math.floor(Math.random() * words.length)];
        const color = colors[Math.floor(Math.random() * colors.length)];
        return word;
      }, 0).color((context) => {
        return colors[Math.floor(Math.random() * colors.length)];
      }))
      .add(ForgeScript.createKeyboardResponse(['f', 'g', 'h'], 5000));

    // Thanks timeline
    const thanks = ForgeScript.createTimeline('thanks')
      .add(ForgeScript.createTextStimulus('Thank you for participating!', 3000));

    experiment.timeline([welcome, instructions, trialTimeline, thanks]);
    return experiment;
  },

  createSimpleRT: (stimuli: string[], trials: number = 50) => {
    const experiment = ForgeScript.createExperiment('Simple Reaction Time')
      .description('Simple reaction time task')
      .author('Generated by ForgeScript');

    const welcome = ForgeScript.createTimeline('welcome')
      .add(ForgeScript.createTextStimulus('Reaction Time Task', 2000))
      .add(ForgeScript.createTextStimulus('Press SPACE when you see a stimulus.\nPress SPACE to start.'))
      .add(ForgeScript.createKeyboardResponse(['space']));

    const trialTimeline = ForgeScript.createTimeline('trials')
      .repeat(trials)
      .add(ForgeScript.createWaitEvent(Math.random() * 2000 + 1000)) // random delay
      .add(ForgeScript.createTextStimulus((context) => {
        return stimuli[Math.floor(Math.random() * stimuli.length)];
      }))
      .add(ForgeScript.createKeyboardResponse(['space'], 5000));

    const thanks = ForgeScript.createTimeline('thanks')
      .add(ForgeScript.createTextStimulus('Task complete!', 2000));

    experiment.timeline([welcome, trialTimeline, thanks]);
    return experiment;
  }
};

// Default export
export default ForgeScript;

# @psyforge/timing

High-precision timing system for psychological experiments, providing microsecond-level accuracy for stimulus presentation and response collection.

## Features

- **≤2ms timing precision** using Web Audio API hardware clock
- **Cross-browser compatibility** (Chrome, Firefox, Safari)
- **Drift detection and monitoring** with real-time precision feedback
- **Frame-accurate display synchronization** via RequestAnimationFrame
- **TypeScript support** with full type safety

## Installation

```bash
npm install @psyforge/timing
```

## Quick Start

```typescript
import { PrecisionClock, TimingDriftDetector } from '@psyforge/timing';

// Initialize the precision clock
const clock = new PrecisionClock();
const context = await clock.initialize();

// Get high-precision timestamps
const timestamp = clock.now();
console.log(`Audio time: ${timestamp.audioTime}s`);
console.log(`Performance time: ${timestamp.performanceTime}ms`);

// Monitor timing drift
const detector = new TimingDriftDetector(clock);
detector.startMonitoring();

// Check drift status
const status = detector.getDriftStatus();
console.log(`Timing accurate: ${status.isAccurate}`);
console.log(`Max jitter: ${status.maxObservedJitter}ms`);
```

## API Reference

### PrecisionClock

The main timing class providing microsecond-level precision.

#### Methods

- `initialize(): Promise<TimingContext>` - Initialize the clock with Web Audio API
- `now(): PrecisionTimestamp` - Get current high-precision timestamp
- `scheduleCallback(targetTime, callback)` - Schedule precise timing callbacks
- `onFrame(callback): () => void` - Register for display frame callbacks
- `getPrecisionEstimate(): number` - Get timing precision estimate in microseconds
- `isHighPrecisionAvailable(): boolean` - Check if high-precision timing is supported
- `destroy(): Promise<void>` - Clean up resources

#### Types

```typescript
interface PrecisionTimestamp {
  readonly audioTime: number;      // Web Audio API time (seconds)
  readonly performanceTime: number; // Performance.now() time (milliseconds)
  readonly rafTime: number;        // RequestAnimationFrame time (milliseconds)
  readonly monotonic: number;      // Combined monotonic timestamp
}
```

### TimingDriftDetector

Monitors timing precision and detects degradation.

#### Methods

- `startMonitoring(): void` - Begin continuous drift monitoring
- `stopMonitoring(): void` - Stop drift monitoring
- `takeMeasurement(): DriftMeasurement` - Take single precision measurement
- `getDriftStatus(): DriftStatus` - Get current drift analysis
- `estimatePrecision(): number` - Estimate timing precision from measurements
- `meetsPrecisionRequirement(required): boolean` - Check if precision meets requirements
- `setThresholds(warning, critical): void` - Set drift warning thresholds

#### Types

```typescript
interface DriftStatus {
  readonly isAccurate: boolean;
  readonly maxObservedJitter: number;
  readonly averageJitter: number;
  readonly driftTrend: number;
  readonly warnings: string[];
  readonly recommendations: string[];
}
```

## Utility Functions

### isTimingSupported()

Check if high-precision timing is supported in the current environment.

```typescript
import { isTimingSupported } from '@psyforge/timing';

if (isTimingSupported()) {
  // Proceed with timing-critical operations
} else {
  // Fallback to lower-precision timing
}
```

### getTimingCapabilities()

Get detailed information about timing capabilities.

```typescript
import { getTimingCapabilities } from '@psyforge/timing';

const capabilities = await getTimingCapabilities();
console.log(`Estimated precision: ${capabilities.estimatedPrecision}μs`);
```

## Browser Support

| Browser | Version | Audio API | Performance API | Notes |
|---------|---------|-----------|-----------------|-------|
| Chrome | 66+ | ✅ | ✅ | Full support |
| Firefox | 60+ | ✅ | ✅ | Full support |
| Safari | 14.1+ | ✅ | ✅ | Full support |
| Edge | 79+ | ✅ | ✅ | Full support |

## Performance Considerations

- **Initialization cost**: ~10-50ms for AudioContext setup
- **Memory usage**: <1MB for typical monitoring sessions
- **CPU overhead**: <0.1% for continuous drift monitoring
- **Precision**: Typically 5-50μs on modern hardware

## Best Practices

### 1. Initialize Early

```typescript
// Initialize during app startup, not during experiments
const clock = new PrecisionClock();
await clock.initialize();
```

### 2. Monitor Drift

```typescript
// Start monitoring before critical timing sections
const detector = new TimingDriftDetector(clock);
detector.startMonitoring();

// Check status periodically
if (!detector.getDriftStatus().isAccurate) {
  console.warn('Timing precision degraded');
}
```

### 3. Handle Errors

```typescript
try {
  await clock.initialize();
} catch (error) {
  // Fallback to performance.now() only
  console.warn('High-precision timing unavailable:', error);
}
```

### 4. Clean Up

```typescript
// Always clean up resources
detector.stopMonitoring();
await clock.destroy();
```

## Timing Validation

The package includes comprehensive timing validation:

```typescript
// Check if precision meets your requirements
const detector = new TimingDriftDetector(clock);
const meetsPrecision = detector.meetsPrecisionRequirement(2.0); // 2ms requirement

if (!meetsPrecision) {
  console.warn('System does not meet 2ms precision requirement');
}
```

## Integration with Experiments

```typescript
class ExperimentTimer {
  private clock: PrecisionClock;
  private detector: TimingDriftDetector;

  async initialize() {
    this.clock = new PrecisionClock();
    await this.clock.initialize();

    this.detector = new TimingDriftDetector(this.clock);
    this.detector.startMonitoring();
  }

  presentStimulus() {
    const startTime = this.clock.now();

    // Schedule precise stimulus offset
    this.clock.scheduleCallback(startTime.audioTime + 0.5, () => {
      this.hideStimulus();
    });

    return startTime;
  }

  checkPrecision() {
    return this.detector.getDriftStatus();
  }

  async destroy() {
    this.detector.stopMonitoring();
    await this.clock.destroy();
  }
}
```

